Greedy regret-based insertion with look-ahead evaluation: prioritize orders with highest insertion cost difference between best and second-best positions, while considering both current cost increase and potential future flexibility through slack time utilization.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type insertOption struct {
		assignIdx int
		costInc   float64
		isValid   bool
	}
	orderOptions := make([][]insertOption, len(oris))

	for oi := range oris {
		options := make([]insertOption, dispatch.AssignsLen+1)
		validCount := 0

		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assignCopy := dispatch.Assigns[ai]
			oldCost := assignCopy.Cost

			if assignCopy.AddShip(total_ship+oi, oris[oi], dess[oi]) {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost

				if newCost >= 0 {
					options[validCount] = insertOption{assignIdx: ai, costInc: newCost - oldCost, isValid: true}
					validCount++
				}
			}
		}

		if dispatch.AssignsLen < MAXASSIGNS {
			var emptyAssign Assign
			if emptyAssign.AddShip(total_ship+oi, oris[oi], dess[oi]) {
				emptyAssign.GenRoute()
				if emptyAssign.Cost >= 0 {
					options[validCount] = insertOption{assignIdx: dispatch.AssignsLen, costInc: emptyAssign.Cost, isValid: true}
					validCount++
				}
			}
		}

		orderOptions[oi] = options[:validCount]
	}

	processed := make([]bool, len(oris))
	remainingOrders := len(oris)

	for remainingOrders > 0 {
		bestOrderIdx := -1
		bestRegretValue := -1e308
		bestChosenAssignIdx := -1

		for oi := range oris {
			if processed[oi] || len(orderOptions[oi]) == 0 {
				continue
			}

			opts := orderOptions[oi]
			if len(opts) == 1 {
				regretVal := opts[0].costInc*100 + 1e6
				if regretVal > bestRegretValue {
					bestRegretValue = regretVal
					bestOrderIdx = oi
					bestChosenAssignIdx = opts[0].assignIdx
				}
			} else {
				firstBestIdx := 0
				secondBestIdx := 1
				if opts[1].costInc < opts[firstBestIdx].costInc {
					firstBestIdx, secondBestIdx = 1, 0
				}
				for k := 2; k < len(opts); k++ {
					if opts[k].costInc < opts[firstBestIdx].costInc {
						secondBestIdx = firstBestIdx
						firstBestIdx = k
					} else if opts[k].costInc < opts[secondBestIdx].costInc {
						secondBestIdx = k
					}
				}
				regretVal := (opts[secondBestIdx].costInc - opts[firstBestIdx].costInc)*10 - opts[firstBestIdx].costInc
				if regretVal > bestRegretValue {
					bestRegretValue = regretVal
					bestOrderIdx = oi
					bestChosenAssignIdx = opts[firstBestIdx].assignIdx
				}
			}
		}

		if bestOrderIdx == -1 {
			break
		}

		chosenAssignIdx := bestChosenAssignIdx
		if chosenAssignIdx >= dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
			dispatch.Assigns[chosenAssignIdx].AddShip(total_ship+bestOrderIdx, oris[bestOrderIdx], dess[bestOrderIdx])
			dispatch.Assigns[chosenAssignIdx].GenRoute()
			if dispatch.Assigns[chosenAssignIdx].Cost >= 0 {
				dispatch.AssignsLen++
			} else {
				dispatch.Assigns[chosenAssignIdx].RemoveShip(total_ship + bestOrderIdx)
				dispatch.Assigns[chosenAssignIdx].GenRoute()
			}
		} else if chosenAssignIdx < dispatch.AssignsLen {
			dispatch.Assigns[chosenAssignIdx].AddShip(total_ship+bestOrderIdx, oris[bestOrderIdx], dess[bestOrderIdx])
			dispatch.Assigns[chosenAssignIdx].GenRoute()
		}

		processed[bestOrderIdx] = true
		remainingOrders--

		for oi := range oris {
			if processed[oi] {
				continue
			}
			validOpts := make([]insertOption, 0)

			for ai := 0; ai < dispatch.AssignsLen; ai++ {
				assignCopy := dispatch.Assigns[ai]
				oldCost := assignCopy.Cost

				if assignCopy.AddShip(total_ship+oi, oris[oi], dess[oi]) {
					assignCopy.GenRoute()
					newCost := assignCopy.Cost

					if newCost >= 0 {
						validOpts = append(validOpts, insertOption{assignIdx: ai, costInc: newCost - oldCost, isValid: true})
					}
				}
			}

			if dispatch.AssignsLen < MAXASSIGNS {
				var emptyAssign Assign
				if emptyAssign.AddShip(total_ship+oi, oris[oi], dess[oi]) {
					emptyAssign.GenRoute()
					if emptyAssign.Cost >= 0 {
						validOpts = append(validOpts, insertOption{assignIdx: dispatch.AssignsLen, costInc: emptyAssign.Cost, isValid: true})
					}
				}
			}

			orderOptions[oi] = validOpts
		}
	}

	for oi := range oris {
		if !processed[oi] {
			seedIdx := dispatch.AssignsLen
			if seedIdx < MAXASSIGNS {
				var emptyAssign Assign
				if emptyAssign.AddShip(total_ship+oi, oris[oi], dess[oi]) {
					emptyAssign.GenRoute()
					if emptyAssign.Cost >= 0 {
						dispatch.Assigns[seedIdx] = emptyAssign
						dispatch.AssignsLen++
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

